# # save as json per era
# for sample, sdict in all_samples.items():
#     with open(f"datasets_{sample}.json", "w") as f:
#         json.dump(sdict, f, indent=4)


# Invert the all_samples dictionary to have years as top-level keys
years_first = {}

for sample, sdict in all_samples.items():
    for year, sample_dict in sdict.items():
        if year not in years_first:
            years_first[year] = {}
        if sample not in years_first[year]:
            years_first[year][sample] = {}
        years_first[year][sample] = sample_dict

# Now years_first is structured as:
# years_first[year][sample_name] = dataset_path

# Optionally, save as json per sample_type
for year, sdict in years_first.items():
    with open(f"datasets_{year}.json", "w") as f:
        json.dump(sdict, f, indent=4)
